export function BotSelector() {
	const { control } = useFormContext<CommandGeneratorFormData>();
	return (
		<Field>
			<FieldLabel htmlFor="bot-selector">Escolha seu bot</FieldLabel>
			<Controller
				name="selectedBot"
				control={control}
				render={({ field }) => (
					<RadioGroup
						value={field.value}
						onValueChange={field.onChange}
						className="grid-cols-1 md:grid-cols-3"
					>
						{bots.map((bot) => (
							<FieldLabel key={bot.id} htmlFor={bot.id}>
								<Field orientation="horizontal">
									<FieldContent>
										<FieldTitle>
											{botIcons[bot.id]} {bot.name}
										</FieldTitle>
									</FieldContent>
									<RadioGroupItem value={bot.id} id={bot.id} />
								</Field>
							</FieldLabel>
						))}
					</RadioGroup>
				)}
			/>
		</Field>
	);
}
